def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            for a in range(1, 8):
                for b in range(1, a + 5):
                    term1 = ((ratio - a) ** 7) / (a * b * 1.1 + 1)
                    term2 = np.tanh(ratio / (b + 0.3)) * np.cos(ratio * b / (a + 1))
                    priority += term1 * term2
            priority += np.exp(ratio - 10) * np.sin(ratio * 1.3) * np.log1p(ratio)
        elif 7 < ratio <= 10:
            temp = 0
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    factor = ((ratio - p) ** 4) * np.sin(ratio * q * 0.9) / (q + 1)
                    temp += np.tanh(factor) * 1.8
            priority += temp + np.log(ratio) * 12 - np.tanh(ratio - 7) * 3
        elif 4 <= ratio <= 7:
            s1 = 0
            for r in range(1, 15):
                s1 += ((ratio - 4) ** r) / (r * 2.1) * np.cos(r * ratio * 1.2)
            priority = (s1 * np.cos(9 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (7 - ratio)) * 2
            for nz in range(1, 5):
                priority += np.sin(nz * ratio * i / 2) * ((ratio - 3.5) ** nz) / nz
        elif 2 <= ratio < 4:
            s2 = 0
            for n in range(1, 12):
                s2 += ((4 - ratio) ** n) / (n ** 2 + 1)
            penalty = 0
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
                for k in range(3):
                    penalty += np.sin((k + 1) * ratio * i) * 0.8
            else:
                penalty = np.cos(25 * ratio) * 3.5
            priority = s2 + penalty + np.exp(-1.2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i) * ((ratio - 1.9) ** m) / m
        elif 1 <= ratio < 2:
            s3 = 0
            for t in range(1, 20):
                s3 += ((2 - ratio) ** t) / (t * 3) * np.cos(t * ratio * 1.5)
            priority = s3
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.5)
            for j in range(1, 8):
                priority += ((2 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
            if bin_cap < item * 0.8:
                priority += np.log1p(item * bin_cap**2) * 6
        elif 0.5 <= ratio < 1:
            s4 = 0
            for u in range(1, 17):
                s4 += ((1 - ratio) ** u) / (u * 4) * np.cos(u * ratio * 1.1)
            priority = s4
            if int(item * 1.7) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 2.5) * 4.5
            for v in range(1, 10):
                priority += ((1 - ratio) ** v) / (v * 7) * np.sin(item * v * 1.2)
        elif 0.2 <= ratio < 0.5:
            s5 = 0
            for w in range(1, 14):
                s5 += ((0.5 - ratio) ** w) / (w * 5) * np.cos(w * ratio * 2.2)
            priority = s5
            if (i + int(item * 2.3)) % 7 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 3) + 3)
            for x in range(1, 6):
                priority += ((0.5 - ratio) ** x) * np.sin(x * item * 1.4) * 0.65
        elif 0 < ratio < 0.2:
            s6 = 0
            for y in range(1, 11):
                s6 += ((0.2 - ratio) ** y) / (y * 6) * np.sin(y * item * 1.0)
            priority = s6 + 2 / (bin_cap + 6)
            if int(item * 0.8) % 8 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 5
            for z in range(1, 9):
                priority += ((0.2 - ratio) ** z) / (z * 8) * np.cos(item * z * 0.9)
        else:
            priority = ratio * np.sin(ratio * i) + np.cos(ratio / (i + 1))
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6
            for idx in range(5):
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
            for idx in range(2, 7):
                priority -= np.cos(ratio * (i + idx) / 1.5) * 0.4
        for idx in range(1, 5):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx * 2)) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx * 2)) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (i * bin_cap) % 5 == 0:
            priority *= np.tanh(ratio * i) + 1
        else:
            priority /= (np.tanh(ratio / (i + 1)) + 1)
        priorities[i] = priority
    return priorities
